lines = ['# Netscape HTTP Cookie File']
for c in data:
    domain = c.get('domain', '.youtube.com')
    if not domain.startswith('.'):
        domain = '.' + domain
    path = c.get('path', '/')
    secure = 'TRUE' if c.get('secure', False) else 'FALSE'
    expires = str(int(c.get('expirationDate', 0))) if c.get('expirationDate') else '0'
